import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as s,e as r}from"./app-9e72bba2.js";const i={},t=r('<h1 id="java面试" tabindex="-1"><a class="header-anchor" href="#java面试" aria-hidden="true">#</a> Java面试</h1><h2 id="自我介绍" tabindex="-1"><a class="header-anchor" href="#自我介绍" aria-hidden="true">#</a> 自我介绍</h2><details class="hint-container details"><summary><b style="color:#bf3e73;">问：自我介绍</b></summary><p><b style="color:#f19977;">答：面试官您好，我叫xxx，现在是湖北文理学院软件工程专业大四学生。对软件开发有浓烈的兴趣。对Java语言比较熟悉，能熟练使用SpringBoot，Vue等目前主流的前后端框架。目前已独立完成了一个音乐网站项目以及搭建自己的个人博客。有一定的实践经验，但实践经验还是比较浅，之后打算做一个个人网站丰富自己的实践经验。</b></p></details><h2 id="基础面试题" tabindex="-1"><a class="header-anchor" href="#基础面试题" aria-hidden="true">#</a> 基础面试题</h2><h3 id="java八大基本类型" tabindex="-1"><a class="header-anchor" href="#java八大基本类型" aria-hidden="true">#</a> Java八大基本类型</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Java八大基本类型</b></summary><p><b style="color:#f19977;">答：Byte Short Int Long Float Double Char Boolean</b></p></details><h3 id="jar包和war包的区别" tabindex="-1"><a class="header-anchor" href="#jar包和war包的区别" aria-hidden="true">#</a> Jar包和War包的区别</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Jar包和War包的区别</b></summary><p><b style="color:#f19977;">答：jar包就是别人写好的一些类，然后对这些类进行打包，开发人员可以将这些jar包引入到自己的项目中，使用这些类和属性。 jar包一般放在lib目录下。war包是一个web模块，可以直接运行，一般开发好的网站，打包后部署到tomcat的网站根目录下，然后重启tomcat，这个包就可以自动解压，相当于代码发布。</b></p></details><h3 id="string类中常用的方法" tabindex="-1"><a class="header-anchor" href="#string类中常用的方法" aria-hidden="true">#</a> String类中常用的方法</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：String类中常用的方法</b></summary><p><b style="color:#f19977;">答：indexof()从指定字符提取索引位置、replace()替换、subString()截取字符串、equals()比较、split()把字符串分割成字符串数组</b></p></details><h3 id="什么是重载和重写" tabindex="-1"><a class="header-anchor" href="#什么是重载和重写" aria-hidden="true">#</a> 什么是重载和重写</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：什么是重载和重写</b></summary><p><b style="color:#f19977;">答：Java里面方法的重写和重载就是指Java的多态。重写就是父类和子类之间的多态，方法名和参数都一样。重载是一个类中方法的多态，方法名相同而参数不同。</b></p></details><h3 id="string中-和equals的区别" tabindex="-1"><a class="header-anchor" href="#string中-和equals的区别" aria-hidden="true">#</a> String中 == 和equals的区别</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：String中的 == 和equals的区别</b></summary><p><b style="color:#f19977;">答：对于八大基本类型 == 比较的是值。对于引用类型来说 == 比较的是内存地址，equals比较的是内容。</b></p></details><h3 id="string-stringbuilder-stringbuffer三者的区别" tabindex="-1"><a class="header-anchor" href="#string-stringbuilder-stringbuffer三者的区别" aria-hidden="true">#</a> String StringBuilder StringBuffer三者的区别</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：String StringBuilder StringBuffer三者的区别</b></summary><p><b style="color:#f19977;">答：在开发中String主要用于少量字符串的操作，因为它是final修饰的，是不可变字符串。StringBuffer主要用于可变的字符串，因为其有append方法。另外它是线程安全的。StringBuilder也是拼接字符串的，初始化创建一个对象，用append进行拼接，不会创建新对象。</b></p></details><h3 id="final关键字" tabindex="-1"><a class="header-anchor" href="#final关键字" aria-hidden="true">#</a> Final关键字</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：说说Final关键字</b></summary><p><b style="color:#f19977;">答：Final是一个安全修饰符，Final修饰的类不能被继承，Final声明的方法不能被重写。Final声明的变量不能被修改。</b></p></details><h3 id="java里可不可以有多继承" tabindex="-1"><a class="header-anchor" href="#java里可不可以有多继承" aria-hidden="true">#</a> Java里可不可以有多继承</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Java里可不可以有多继承</b></summary><p><b style="color:#f19977;">答：不可以，想多继承的话用接口</b></p></details><h3 id="java三大特性" tabindex="-1"><a class="header-anchor" href="#java三大特性" aria-hidden="true">#</a> Java三大特性</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Java三大特性</b></summary><p><b style="color:#f19977;">答：分别是封装、继承、多态。封装就是把一个事物有的方法和属性封装成对象。继承的体现就是让我们可以复用父类里面的代码。多态就是Java里面的继承、重写、重载。</b></p></details><h3 id="arraylist的底层" tabindex="-1"><a class="header-anchor" href="#arraylist的底层" aria-hidden="true">#</a> ArrayList的底层</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：ArrayList的底层</b></summary><p><b style="color:#f19977;">答：ArrayList是基于数组实现的，是一个动态数组。底层维护了一个Object类型的数组elementData。如果使用无参构造器，则初始elementData容量为0，第一次添加扩容为10，之后如需再次扩容，则扩容为elementData的1.5倍。如果使用指定大小的构造器则初始elementData容量为指定大小，如果需要扩容，则直接扩容为elementData的1.5倍。另外ArrayList是线程不安全的。</b></p></details><h3 id="arraylist与linkedlist的区别" tabindex="-1"><a class="header-anchor" href="#arraylist与linkedlist的区别" aria-hidden="true">#</a> ArrayList与LinkedList的区别</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：ArrayList与LinkedList的区别</b></summary><p><b style="color:#f19977;">答：ArrayList使用数组的方式存储数据，所以根据索引查询数据速度快，而增加和删除时需要移位操作所以慢。LinkedList使用双向链接的方式存储数据，所以插入和删除数据时只需更改前后元素的指针指向即可，速度非常快。</b></p></details><h3 id="hashmap的底层实现原理" tabindex="-1"><a class="header-anchor" href="#hashmap的底层实现原理" aria-hidden="true">#</a> HashMap的底层实现原理</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：HashMap的底层实现原理</b></summary><p><b style="color:#f19977;">答：HashMap的底层是数组+链表+红黑树。数组的初始大小是16，每个数组存储着一个链表。存数据时先根据Key的hashcode值计算出hash值，然后用hash值确定在数组中的位置，如果此位置没有东西则直接放入，如果有就会生成链表，把新的放入链表尾部。当取值时，会先根据Key的hashcode值计算出hash值，确定在数组中的位置，再根据equals方法从该位置上的链表中取出value值。如果数组的长度大于64并且链表的长度大于8就会树化成红黑树。数组扩容倍数是2倍。</b></p></details><h3 id="泛型" tabindex="-1"><a class="header-anchor" href="#泛型" aria-hidden="true">#</a> 泛型</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：泛型</b></summary><p><b style="color:#f19977;">答：泛型是JDK1.5以后有的，我觉得它的好处就是让集合变得更安全一些，省去了强制转换。</b></p></details><h3 id="说五个开发中常见的异常" tabindex="-1"><a class="header-anchor" href="#说五个开发中常见的异常" aria-hidden="true">#</a> 说五个开发中常见的异常</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：说五个开发中常见的异常</b></summary><p><b style="color:#f19977;">答：IO异常、空指针异常、数组下标越界异常、文件未找到异常、Sql异常</b></p></details><h3 id="java实现多线程的方法" tabindex="-1"><a class="header-anchor" href="#java实现多线程的方法" aria-hidden="true">#</a> Java实现多线程的方法</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Java实现多线程的方法</b></summary><p><b style="color:#f19977;">答：继承Thread类、因为Java是单继承。所以还可以实现Runnable接口</b></p></details><h3 id="多线程怎么解决高并发" tabindex="-1"><a class="header-anchor" href="#多线程怎么解决高并发" aria-hidden="true">#</a> 多线程怎么解决高并发</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：多线程怎么解决高并发</b></summary><p><b style="color:#f19977;">答：有两种。一种是Synchronized是利用锁的机制，使变量和代码块在某一时只能被一个线程访问。二是ThreadLocal其为每一个线程都提供变量的副本，使得每个线程在某一时间访问到的并不是同一对象，这样就隔离了多个线程对数据的数据共享。</b></p></details><h3 id="jvm内存分析-解释下堆和栈" tabindex="-1"><a class="header-anchor" href="#jvm内存分析-解释下堆和栈" aria-hidden="true">#</a> JVM内存分析，解释下堆和栈</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：JVM内存分析，解释下堆和栈</b></summary><p><b style="color:#f19977;">答：JVM内存结构主要分为堆内存、方法区和栈。堆内存时JVM中最大的一块内存地址。所有new出来的对象都存储在该区域。栈就是暂存数据的地方，栈中只保存基础数据类型的对象和自定义对象的引用，每个栈中的数据都是私有的，其它栈不能访问。方法区存放了要加载的类的信息如类名、修饰符、静态变量、构造函数等</b></p></details><h3 id="什么是反射-能干嘛" tabindex="-1"><a class="header-anchor" href="#什么是反射-能干嘛" aria-hidden="true">#</a> 什么是反射，能干嘛</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：什么是反射，能干嘛</b></summary><p><b style="color:#f19977;">答：反射就是将类的各个组成部分封装成其它对象。在Java中只要知道类的名字，通过Class.forName方法可以获得到类对象。通过Class类对象就可以获得类的所有信息。比如类中的成员变量和方法。我们可以对类里的这些方法进行执行或者用动态代理模式进行增强。我们常用的Spring和MyBatis框架就是利用Java反射+动态代理的技术编写的。</b></p></details><h3 id="get和post请求的区别" tabindex="-1"><a class="header-anchor" href="#get和post请求的区别" aria-hidden="true">#</a> Get和Post请求的区别</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Get和Post请求的区别</b></summary><p><b style="color:#f19977;">答：Get是用URL传递数据的，不是很安全。而且传递的数据量比较小。Post是可以传递大数据量的。</b></p></details><h3 id="session和cookie的区别" tabindex="-1"><a class="header-anchor" href="#session和cookie的区别" aria-hidden="true">#</a> Session和Cookie的区别</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Session和Cookie的区别</b></summary><p><b style="color:#f19977;">答：Session是保存到服务器端的。Cookie是保存到客户端上的。Session相对于Cookie来说更安全。</b></p></details><h3 id="转发和重定向的区别" tabindex="-1"><a class="header-anchor" href="#转发和重定向的区别" aria-hidden="true">#</a> 转发和重定向的区别</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：转发和重定向的区别</b></summary><p><b style="color:#f19977;">答：重定向就是RequestDispatcher.forward只能将请求转发给同一个项目中而且可以携带数据。而转发可以跳转到当前项目中的页面也可以跳转到其他项目中的页面但是不能携带数据。</b></p></details><h3 id="类的初始化过程" tabindex="-1"><a class="header-anchor" href="#类的初始化过程" aria-hidden="true">#</a> 类的初始化过程</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：类的初始化过程</b></summary><p><b style="color:#f19977;">答：加载Class文件进内存，在栈内存开辟空间，在堆内存为对象开辟空间，对对象的成员变量进行默认初始化，对对象的成员变量进行显示初始化。通过构造方法对对象的成员变量赋值，把对象地址赋值给变量。</b></p></details><h3 id="为什么要同时重写hashcode和equals方法" tabindex="-1"><a class="header-anchor" href="#为什么要同时重写hashcode和equals方法" aria-hidden="true">#</a> 为什么要同时重写HashCode和Equals方法</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：为什么要同时重写HashCode和Equals方法</b></summary><p><b style="color:#f19977;">答：重写Equals方法是为了比较两个不同对象的值是否相等。重写HashCode方法是为了让同一个Class对象的两个具有相同值的对象的Hash值相等。同时重写HashCode和Equals是为了满足HashMap等集合的相同对象的不重复存储。</b></p></details><h2 id="后端框架" tabindex="-1"><a class="header-anchor" href="#后端框架" aria-hidden="true">#</a> 后端框架</h2><h3 id="对spring的理解" tabindex="-1"><a class="header-anchor" href="#对spring的理解" aria-hidden="true">#</a> 对Spring的理解</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：对Spring的理解</b></summary><p><b style="color:#f19977;">答：Spring核心思想为IOC、DI、AOP。Spring框架使用了Java里面的反射机制。IOC就是把对象的创建控制权转移到IOC容器并且负责对象的创建、初始化等一系列工作。被创建的对象在IOC容器中称为Bean。在容器中建立Bean与Bean之间的关系就称为依赖注入。AOP底层是代理模式，可以在不改变原有代码结构的情况下增强功能。</b></p></details><h3 id="aop有哪些应用场景" tabindex="-1"><a class="header-anchor" href="#aop有哪些应用场景" aria-hidden="true">#</a> AOP有哪些应用场景</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：AOP有哪些应用场景</b></summary><p><b style="color:#f19977;">答：事务管理、日志打印。</b></p></details><h3 id="spring-中-autowired-和-resource-的区别" tabindex="-1"><a class="header-anchor" href="#spring-中-autowired-和-resource-的区别" aria-hidden="true">#</a> Spring 中@Autowired 和@Resource 的区别?</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Spring 中@Autowired 和@Resource 的区别?</b></summary><p><b style="color:#f19977;">答：@Autowired是按照类型进行注入，没有类型会按照名称进行注入。@Resource会按照名称注入，名称找不着会按照类型来找。</b></p></details><h3 id="说一下springboot" tabindex="-1"><a class="header-anchor" href="#说一下springboot" aria-hidden="true">#</a> 说一下SpringBoot</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：说一下SpringBoot</b></summary><p><b style="color:#f19977;">答：SpringBoot一个重要的思想是约定大于配置，其整合了所有的后端框架。优点有能快速创建独立运行的Spring项目以及与主流框架集成。大量的自动配置，简化开发。无需配置大量的XML文件，开箱即用。</b></p></details><h3 id="spring的三种注入方式" tabindex="-1"><a class="header-anchor" href="#spring的三种注入方式" aria-hidden="true">#</a> Spring的三种注入方式</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Spring的三种注入方式</b></summary><p><b style="color:#f19977;">答：配置包扫描、seter方式和构造方法的方式</b></p></details><h3 id="为什么bean要设计成单例" tabindex="-1"><a class="header-anchor" href="#为什么bean要设计成单例" aria-hidden="true">#</a> 为什么Bean要设计成单例</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：为什么Bean要设计成单例</b></summary><p><b style="color:#f19977;">答：资源利用效率：单例模式可以节省系统资源，避免重复创建和销毁对象。当一个对象被多次请求时，只需要创建一次实例并重复使用，提高了系统的资源利用效率。对象一致性：对于某些需要保持一致状态或共享数据的对象，使用单例模式可以确保全局只有一个实例。这样可以避免多个实例之间的数据不一致性问题，简化了数据管理和同步的复杂性。全局访问性：单例模式使得对象在整个应用程序的上下文中可被访问。这对于需要在不同的组件或模块中共享数据或提供共享服务的对象非常有用。配置和管理简便性：在Spring框架中，Bean的单例模式使得对象的创建、依赖注入和生命周期管理更加简便。通过Spring容器的管理，可以统一配置和管理Bean的创建和销毁过程。</b></p></details><h2 id="数据库" tabindex="-1"><a class="header-anchor" href="#数据库" aria-hidden="true">#</a> 数据库</h2><h3 id="介绍一下redis" tabindex="-1"><a class="header-anchor" href="#介绍一下redis" aria-hidden="true">#</a> 介绍一下Redis</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：介绍一下Redis</b></summary><p><b style="color:#f19977;">答：Redis是一个非关系型数据库。项目中主要用它来存储热点数据，减轻数据库的压力。有很多地方都用到了Redis，比如商品的秒杀，首页热点数据的显示等等。</b></p></details><h3 id="项目中是怎么操作redis的" tabindex="-1"><a class="header-anchor" href="#项目中是怎么操作redis的" aria-hidden="true">#</a> 项目中是怎么操作Redis的</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：项目中是怎么操作Redis的</b></summary><p><b style="color:#f19977;">答：通过SpringData操作Redis</b></p></details><h3 id="redis的数据类型" tabindex="-1"><a class="header-anchor" href="#redis的数据类型" aria-hidden="true">#</a> Redis的数据类型</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Redis的数据类型</b></summary><p><b style="color:#f19977;">答：String、List、Set、Hash、SortedSte有序集合</b></p></details><h3 id="redis是如何同步的" tabindex="-1"><a class="header-anchor" href="#redis是如何同步的" aria-hidden="true">#</a> Redis是如何同步的</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Redis是如何同步的</b></summary><p><b style="color:#f19977;">答：两种解决方案，先更新数据库再更新缓存。但是更新缓存失败的话也不能实现数据同步。第二种是先删除缓存再更新数据库，但由于这两步操作不是原子性的也有可能会失败。</b></p></details><h3 id="解释一下什么是索引" tabindex="-1"><a class="header-anchor" href="#解释一下什么是索引" aria-hidden="true">#</a> 解释一下什么是索引</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：解释一下什么是索引</b></summary><p><b style="color:#f19977;">答：索引可以理解为数据的查询目录，建索引的目的就是为了提高对表的查询速度。</b></p></details><h3 id="sql优化" tabindex="-1"><a class="header-anchor" href="#sql优化" aria-hidden="true">#</a> SQL优化</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：SQL优化</b></summary><p><b style="color:#f19977;">答：使用合适的索引、优化查询语句、避免全表扫描、</b></p></details><h2 id="项目相关" tabindex="-1"><a class="header-anchor" href="#项目相关" aria-hidden="true">#</a> 项目相关</h2><h3 id="token登录流程" tabindex="-1"><a class="header-anchor" href="#token登录流程" aria-hidden="true">#</a> token登录流程</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：token登录流程</b></summary><p><b style="color:#f19977;">答：把用户名和密码通过请求发送到后端，后端验证用户名和密码，验证成功后生成token返回给前端，前端把token保存到本地存储，每次请求前，通过axios请求拦截器，统一发送token。通过vue导航守卫，和axios响应拦截器，统一保护页面。</b></p></details><h2 id="算法" tabindex="-1"><a class="header-anchor" href="#算法" aria-hidden="true">#</a> 算法</h2><h3 id="冒泡排序" tabindex="-1"><a class="header-anchor" href="#冒泡排序" aria-hidden="true">#</a> 冒泡排序</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：冒泡排序</b></summary><p><b style="color:#f19977;">答：比较相邻的两个元素，如果第一个比第二个大，则交换。每一次循环最后面的就是最大的。重复以上步骤。</b></p></details>',82),l=[t];function d(n,h){return e(),s("div",null,l)}const b=a(i,[["render",d],["__file","Java面试.html.vue"]]);export{b as default};
